import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Segnalazioni dei Crash","description":"Impara cosa fare con le segnalazioni di crash, e come leggerle.","frontmatter":{"title":"Segnalazioni dei Crash","description":"Impara cosa fare con le segnalazioni di crash, e come leggerle.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"it_it/1.20.4/players/troubleshooting/crash-reports.md","filePath":"versions/1.20.4/translated/it_it/players/troubleshooting/crash-reports.md","lastUpdated":1766341111000}`);var a={name:`it_it/1.20.4/players/troubleshooting/crash-reports.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Segnalazioni dei Crash <a class="header-anchor" href="#h1" aria-label="Permalink to “Segnalazioni dei Crash”">​</a></h1><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Se hai difficoltà nel trovare la causa del crash, puoi chiedere aiuto nel <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord di Fabric</a> nei canali <code>#player-support</code> o <code>#server-admin-support</code>.</p></div><p>Le segnalazioni di crash, o degli arresti anomali, sono una parte molto importante della risoluzione di problemi con il tuo gioco o server. Contengono molte informazioni riguardanti il crash, e ti possono aiutare a trovare la causa del crash.</p><h2 id="trovare-le-segnalazioni-di-crash" tabindex="-1">Trovare le Segnalazioni di Crash <a class="header-anchor" href="#trovare-le-segnalazioni-di-crash" aria-label="Permalink to “Trovare le Segnalazioni di Crash”">​</a></h2><p>Le segnalazioni di crash sono salvate nella cartella <code>crash-reports</code> nella tua cartella del gioco. Se stai usando un server, essi sono salvati nella cartella <code>crash-reports</code> nella cartella del server.</p><p>Per launcher di terze parti, dovresti affidarti alla loro documentazione per sapere dove trovare le segnalazioni di crash.</p><p>Le segnalazioni di crash possono essere trovate nelle seguenti posizioni:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-23" id="tab-24" checked><label data-title="Windows" for="tab-24">Windows</label><input type="radio" name="group-23" id="tab-25"><label data-title="macOS" for="tab-25">macOS</label><input type="radio" name="group-23" id="tab-26"><label data-title="Linux" for="tab-26">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/crash-reports</span></span></code></pre></div></div></div><h2 id="leggere-le-segnalazioni-di-crash" tabindex="-1">Leggere le Segnalazioni di Crash <a class="header-anchor" href="#leggere-le-segnalazioni-di-crash" aria-label="Permalink to “Leggere le Segnalazioni di Crash”">​</a></h2><p>Le segnalazioni di crash sono molto lunghe, e possono causare confusione nella lettura. Tuttavia, contengono tante informazioni riguardanti il crash, e ti possono aiutare a trovare la causa del crash.</p><p>Per questa guida, useremo <a href="https://github.com/FabricMC/fabric-docs/blob/main/public/assets/players/crash-report-example.log" target="_blank" rel="noreferrer">questa segnalazione di crash come esempio</a>.</p><h3 id="sezioni-della-segnalazione-di-crash" tabindex="-1">Sezioni della Segnalazione di Crash <a class="header-anchor" href="#sezioni-della-segnalazione-di-crash" aria-label="Permalink to “Sezioni della Segnalazione di Crash”">​</a></h3><p>Le segnalazioni di crash consistono di varie sezioni, ciascuna separata con un&#39;intestazione:</p><ul><li><code>---- Minecraft Crash Report ----</code>, il riassunto della segnalazione. Questa sezione contiene l&#39;errore principale che ha causato il crash, l&#39;orario al quale è avvenuto, e la stack trace pertinente. Questa è la sezione più importante della segnalazione del crash poiché lo stack trace potrebbe solitamente contenere riferimenti alla mod che ha causato il crash.</li><li><code>-- Last Reload --</code>, questa sezione non è davvero utile tranne se il crash è avvenuto durante un ricaricamento delle risorse (<kbd>F3</kbd>+<kbd>T</kbd>). Questa sezione conterrà probabilmente l&#39;orario dell&#39;ultimo ricaricamento, e lo stack trace pertinente di qualsiasi errore che si sia verificato durante il processo di ricaricamento. Questi errori sono solitamente causati dai pacchetti risorse, e possono essere ignorati tranne se stanno causando problemi con il gioco.</li><li><code>-- System Details --</code>, questa sezione contiene informazioni riguardo al tuo sistema, come il sistema operativo, la versione di Java, e la quantità di memoria allocata al gioco. Questa sezione è utile per determinare se stai usando la versione corretta di Java, e se hai allocato abbastanza memoria al gioco. <ul><li>In questa sezione, Fabric avrà incluso una linea personalizzata che dice <code>Fabric Mods:</code>, seguita da una lista di tutte le mod che hai installato. Questa sezione è utile per determinare se possibili conflitti potrebbero essersi verificati tra mod.</li></ul></li></ul><h3 id="comprendere-la-segnalazione-del-crash" tabindex="-1">Comprendere la Segnalazione del Crash <a class="header-anchor" href="#comprendere-la-segnalazione-del-crash" aria-label="Permalink to “Comprendere la Segnalazione del Crash”">​</a></h3><p>Ora che sappiamo cos&#39;è ciascuna sezione della segnalazione di crash, possiamo iniziare a suddividere la segnalazione di crash e trovare la causa del crash.</p><p>Usando l&#39;esempio del link sopra, possiamo analizzare la segnalazione di crash e trovare la causa del crash, incluse le mod che l&#39;hanno causato.</p><p>Lo stack trace nella sezione <code>---- Minecraft Crash Report ----</code> è il più importante in questo caso, poiché contiene l&#39;errore principale che ha causato il crash. In questo caso, l&#39;errore è <code>java.lang.NullPointerException: Cannot invoke &quot;net.minecraft.class_2248.method_9539()&quot; because &quot;net.minecraft.class_2248.field_10540&quot; is null</code>.</p><p>Con la quantità di mod menzionata nello stack trace, può essere difficile puntare il dito, ma la prima cosa da fare è cercare la mod che ha causato il crash.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>at snownee.snow.block.ShapeCaches.get(ShapeCaches.java:51)</span></span>
<span class="line"><span>at snownee.snow.block.SnowWallBlock.method_9549(SnowWallBlock.java:26) // [!code focus]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>at me.jellysquid.mods.sodium.client.render.chunk.compile.pipeline.BlockOcclusionCache.shouldDrawSide(BlockOcclusionCache.java:52)</span></span>
<span class="line"><span>at link.infra.indium.renderer.render.TerrainBlockRenderInfo.shouldDrawFaceInner(TerrainBlockRenderInfo.java:31)</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>In questo caso, la mod che ha causato il crash è <code>snownee</code>, poiché è la prima mod menzionata nello stack trace.</p><p>Tuttavia, con la quantità di mod menzionata, potrebbe significare che ci sono problemi di compatibilità tra le mod, e che la mod che ha causato il crash potrebbe non essere la mod colpevole. In questo caso, è meglio segnalare il crash all&#39;autore della mod, e lasciarglielo investigare.</p><h2 id="crash-che-coinvolgono-mixin" tabindex="-1">Crash che coinvolgono Mixin <a class="header-anchor" href="#crash-che-coinvolgono-mixin" aria-label="Permalink to “Crash che coinvolgono Mixin”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>I mixin sono un modo che hanno le mod per modificare il gioco senza dover modificarne il codice sorgente. Sono usati da varie mod, e sono uno strumento molto potente per gli sviluppatori di mod.</p></div><p>Quando un mixin causa un crash, esso menzionerà solitamente il mixin nello stack trace, e la classe che il mixin sta modificando.</p><p>I metodi mixin conterranno <code>mod-id$handlerName</code> nello stack trace, mentre <code>mod-id</code> è l&#39;ID della mod, e <code>handlerName</code> è il nome del gestore del mixin.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>... net.minecraft.class_2248.method_3821$$$mod-id$handlerName() ... // [!code focus]</span></span></code></pre></div><p>Puoi usare queste informazioni per trovare la mod che ha causato il crash, e segnalare il crash all&#39;autore della mod.</p><h2 id="cosa-fare-delle-segnalazioni-di-crash" tabindex="-1">Cosa Fare delle Segnalazioni di Crash <a class="header-anchor" href="#cosa-fare-delle-segnalazioni-di-crash" aria-label="Permalink to “Cosa Fare delle Segnalazioni di Crash”">​</a></h2><p>La migliore cosa da fare con le segnalazioni di crash è caricarle a un paste site, e poi condividere il link con l&#39;autore della mod, o tramite il suo issue tracker o attraverso qualche mezzo di comunicazione (Discord ecc...).</p><p>Questo permetterà all&#39;autore della mod d&#39;investigare il crash, potenzialmente di riprodurlo, e di risolvere il problema che l&#39;ha causato.</p><p>Paste site comuni usati frequentemente per le segnalazioni di crash sono:</p><ul><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,33)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};